/* ═══════ DECOMPRESS DISTRICTS ═══════ */
async function decompressB64Gzip(b64str) {
  const bin = Uint8Array.from(atob(b64str), c => c.charCodeAt(0));
  const ds = new DecompressionStream("gzip");
  const writer = ds.writable.getWriter();
  writer.write(bin); writer.close();
  const reader = ds.readable.getReader();
  const chunks = []; let done = false;
  while (!done) { const r = await reader.read(); if (r.value) chunks.push(r.value); done = r.done; }
  const merged = new Uint8Array(chunks.reduce((a, c) => a + c.length, 0));
  let offset = 0; for (const c of chunks) { merged.set(c, offset); offset += c.length; }
  return JSON.parse(new TextDecoder().decode(merged));
}

