/* ═══════ TOPO DECODER ═══════ */
function dTopo(t){const{arcs,transform:tx}=t;const da=[];for(const a of arcs){const c=[];let x=0,y=0;for(const[dx,dy]of a){x+=dx;y+=dy;c.push(tx?[x*tx.scale[0]+tx.translate[0],y*tx.scale[1]+tx.translate[1]]:[x,y]);}da.push(c);}return da;}
function aC(da,i){return i>=0?da[i].slice():da[~i].slice().reverse();}
function rC(da,r){const c=[];for(const i of r){const a=aC(da,i);c.push(...(c.length?a.slice(1):a));}return c;}
function gC(da,g){if(g.type==="Polygon")return{type:"Polygon",coordinates:g.arcs.map(r=>rC(da,r))};if(g.type==="MultiPolygon")return{type:"MultiPolygon",coordinates:g.arcs.map(p=>p.map(r=>rC(da,r)))};return null;}
function tFC(t,o){const da=dTopo(t);return{type:"FeatureCollection",features:t.objects[o].geometries.map(g=>({type:"Feature",id:g.id,properties:g.properties||{},geometry:gC(da,g)})).filter(f=>f.geometry)};}

/* ═══════ S&P BENCHMARK ═══════ */
const SP500={1981:100,1985:180,1987:210,1989:310,1991:405,1993:490,1995:670,1996:825,1997:1100,1998:1415,1999:1715,2001:1320,2002:1030,2003:1325,2005:1535,2007:1830,2008:1150,2009:1460,2011:1530,2012:1775,2013:2350,2015:2390,2017:3200,2018:3060,2019:4025,2020:4765,2021:6135,2023:7270,2024:8150,2025:8600,2026:9000};
function sp500Cagr(ey){const keys=Object.keys(SP500).map(Number).filter(y=>y<=ey);const start=SP500[keys[keys.length-1]]||100;const end=SP500[2026]||9000;const yrs=2026-ey;if(!start||yrs<=0)return 10.5;return(Math.pow(end/start,1/yrs)-1)*100;}
function sp500CagrYrs(yrs){return yrs<=0?10.5:sp500Cagr(2026-yrs);}

